mapper.select:
	/* com.erns.coching.banner.mapper.BannerMasterDAO.getList */

	SELECT B.* FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT

			FROM T_BANNER_MST AA



			ORDER BY AA.BANNER_MST_CD
		) A
	) B

    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.banner.mapper.BannerMasterDAO.load */

SELECT

FROM T_BANNER_MST AA


	AA.BANNER_MST_CD = #{bannerMstCd, jdbcType=VARCHAR}

mapper.insert:
    	/* com.erns.coching.banner.mapper.BannerMasterDAO.insert */

    	INSERT INTO T_BANNER_MST (
    		  BANNER_MST_CD
			, BANNER_TYPE
			, BANNER_MST_NAME
			, BANNER_MST_DESC
			, USE_YN
			, WIDTH
			, HEIGHT
			, PREVIEW_URL

			, RGTR
			, RGT_DTTM
			, CHNR
			, CHNG_DTTM
    	) VALUES (
    		  #{bannerMstCd		, jdbcType=VARCHAR}
			, #{bannerType		, jdbcType=VARCHAR}
			, #{bannerMstName	, jdbcType=VARCHAR}
			, #{bannerMstDesc	, jdbcType=VARCHAR}
			, COALESCE(#{useYn		, jdbcType=CHAR}, 'Y')
			, COALESCE(#{width		, jdbcType=INTEGER}, 0)
			, COALESCE(#{height		, jdbcType=INTEGER}, 0)
			, #{previewUrl		, jdbcType=VARCHAR}

			, #{rgtr			, jdbcType=INTEGER}
			, now()
			, #{chnr			, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.banner.mapper.BannerMasterDAO.update */

    	UPDATE T_BANNER_MST SET
			  BANNER_TYPE  		= 	#{bannerType	, jdbcType=VARCHAR}
			, BANNER_MST_NAME  	= 	#{bannerMstName	, jdbcType=VARCHAR}
			, BANNER_MST_DESC  	= 	#{bannerMstDesc	, jdbcType=VARCHAR}
			, USE_YN         	= 	COALESCE(#{useYn		, jdbcType=CHAR}, USE_YN)
			, WIDTH    			= 	COALESCE(#{width		, jdbcType=INTEGER}, 0)
			, HEIGHT    		= 	COALESCE(#{height	, jdbcType=INTEGER}, 0)
			, PREVIEW_URL    	= 	#{previewUrl	, jdbcType=VARCHAR}


			, CHNR			 	=  #{chnr			, jdbcType=INTEGER}
			, CHNG_DTTM		 	=  now()

			BANNER_MST_CD 		= #{bannerMstCd, jdbcType=VARCHAR}

    	/* com.erns.coching.banner.mapper.BannerMasterDAO.updateUseYn */

    	UPDATE T_BANNER_MST SET
			  USE_YN         = 	COALESCE(#{useYn, jdbcType=CHAR}, 'N')

			, CHNR			 =  #{chnr	   , jdbcType=INTEGER}
			, CHNG_DTTM		 =  now()

			BANNER_MST_CD = #{bannerMstCd, jdbcType=VARCHAR}

		/* com.erns.coching.banner.mapper.BannerMasterDAO.updateUseYn */

    	UPDATE T_BANNER_MST SET
			  USE_YN         = 	COALESCE(#{useYn, jdbcType=CHAR}, 'N')
			, BANNER_MST_DESC  	= 	#{bannerMstDesc	, jdbcType=VARCHAR}

			, CHNR			 =  #{chnr	   , jdbcType=INTEGER}
			, CHNG_DTTM		 =  now()

			BANNER_MST_CD = #{bannerMstCd, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.banner.mapper.BannerMasterDAO.delete */

DELETE FROM T_BANNER_MST

	AND BANNER_MST_CD = #{bannerMstCd, jdbcType=VARCHAR}
